import osimport timeimport jsonimport hashlibfrom datetime import datetime, timedeltafrom PyQt6.QtCore import QThread, pyqtSignal, QSettingsfrom core.vector_db import VectorDatabasefrom core.embeddings import EmbeddingFactoryclass IndexerWorker(QThread):    progress_signal = pyqtSignal(int, int, str)    log_signal = pyqtSignal(str, str)    finished_signal = pyqtSignal()    error_signal = pyqtSignal(str)    def __init__(self, project_path, file_manager, silent=False):        super().__init__()        self.project_path = project_path        self.file_manager = file_manager        self.silent = silent         self.db = None        self.embed_provider = None        self.is_running = True        self.settings = QSettings("VibeCoder", "Preferences")    def calculate_md5(self, file_path):        hash_md5 = hashlib.md5()        try:            with open(file_path, "rb") as f:                for chunk in iter(lambda: f.read(4096), b""):                    hash_md5.update(chunk)            return hash_md5.hexdigest()        except Exception:            return ""    def _get_logical_day(self):        """        Возвращает логическую дату для квот Google.        Квоты обнуляются в 10:00 (00:00 PT).        До 10:00 утра считается "вчерашний" день квот.        """        now = datetime.now()        if now.hour < 10:            logical_date = now - timedelta(days=1)            return logical_date.strftime("%Y-%m-%d")        return now.strftime("%Y-%m-%d")    def run(self):        try:            self.db = VectorDatabase(self.project_path)                        try:                self.embed_provider, log_msg = EmbeddingFactory.get_provider("Gemini")                if not self.silent:                    self.log_signal.emit(log_msg, "#e6a822")            except Exception as e:                self.error_signal.emit(f"Ошибка провайдера эмбеддингов: {e}")                return                            files_to_index = self._gather_files()            indexed_files = self.db.get_indexed_files()            rel_files_to_index = set(os.path.relpath(f, self.project_path).replace('\\', '/') for f in files_to_index)                        files_to_delete = []            for indexed_path in indexed_files.keys():                if indexed_path not in rel_files_to_index:                    files_to_delete.append(indexed_path)                                if files_to_delete:                if not self.silent:                    self.log_signal.emit(f"🗑️ Очистка базы: найдено {len(files_to_delete)} удаленных/игнорируемых файлов. Удаляем старые векторы...", "#d32f2f")                for path_to_del in files_to_delete:                    if not self.is_running: break                    self.db.delete_file_chunks(path_to_del)                                indexed_files = self.db.get_indexed_files()            total_files = len(files_to_index)            if total_files == 0:                if not self.silent: self.log_signal.emit("Нет файлов для индексации.", "#888888")                self.finished_signal.emit()                return            if not self.silent:                self.log_signal.emit(f"Начата RAG-индексация проекта ({total_files} файлов)...", "#31a24c")                            processed_count = 0            skipped_count = 0            is_quota_error = False                        for i, file_path in enumerate(files_to_index):                if not self.is_running:                    if not self.silent: self.log_signal.emit("Индексация остановлена.", "#e6a822")                    break                                    rel_path = os.path.relpath(file_path, self.project_path).replace('\\', '/')                if not self.silent: self.progress_signal.emit(i + 1, total_files, rel_path)                                current_hash = self.calculate_md5(file_path)                                if rel_path in indexed_files:                    old_hash = indexed_files[rel_path]                    if old_hash == current_hash and current_hash != "":                        skipped_count += 1                        continue                    else:                        if not self.silent: self.log_signal.emit(f"🔄 Файл {rel_path} изменен. Обновляем векторы...", "#00838f")                        self.db.delete_file_chunks(rel_path)                                        try:                    self._process_file(file_path, rel_path, current_hash)                    processed_count += 1                    time.sleep(0.5)                 except Exception as e:                    # 🚨 ЖЕСТКИЙ СТОП при критических ошибках API                    if "QUOTA_EXCEEDED" in str(e) or "CRITICAL_API_ERROR" in str(e):                        is_quota_error = True                        break                                            if not self.silent: self.log_signal.emit(f"Ошибка индексации {rel_path}: {e}", "#ff4444")            if is_quota_error:                if not self.silent and processed_count > 0:                    self.log_signal.emit(f"До прерывания успели обработать: {processed_count} файлов.", "#ffaa00")                return             if self.is_running and not self.silent:                self.log_signal.emit(f"Индексация завершена. Добавлено/Обновлено: {processed_count}. Пропущено (без изменений): {skipped_count}. Удалено: {len(files_to_delete)}", "#31a24c")                            self.finished_signal.emit()        except Exception as e:            self.error_signal.emit(str(e))    def _gather_files(self):        allowed_extensions = {            '.py', '.js', '.html', '.css', '.md', '.txt', '.json',             '.bat', '.sh', '.cpp', '.c', '.h', '.java', '.go'        }        files = []        from core.file_explorer import GitIgnoreModel        ignore_checker = GitIgnoreModel(self.project_path)                for root, _, filenames in os.walk(self.project_path):            if not self.is_running: break            for filename in filenames:                file_path = os.path.join(root, filename)                ext = os.path.splitext(filename)[1].lower()                                if ext in allowed_extensions and not ignore_checker.is_ignored_for_rag(file_path):                    files.append(file_path)        return files    def _process_file(self, abs_path, rel_path, file_hash):        with open(abs_path, 'r', encoding='utf-8') as f:            content = f.read()                    if not content.strip(): return                lines = content.split('\n')        chunk_size = 40        overlap = 10        chunks = []                for i in range(0, len(lines), chunk_size - overlap):            chunk = '\n'.join(lines[i:i + chunk_size])            if chunk.strip():                chunks.append(chunk)                        ids = []        embeddings = []        texts = []        metadatas = []        current_time = datetime.now().strftime("%Y-%m-%d %H:%M:%S")                for i, chunk in enumerate(chunks):            if not self.is_running: return            context_text = f"Файл: {rel_path}\nКод:\n{chunk}"                        vector = None            max_retries = 5            base_delay = 5                        for attempt in range(max_retries):                if not self.is_running: return                try:                    current_key = getattr(self.embed_provider, 'api_key', 'unknown')                    vector = self.embed_provider.get_embedding(context_text)                                        # --- УМНЫЙ УЧЕТ ЛИМИТОВ (Сброс в 10:00) ---                    logical_today = self._get_logical_day()                                        if self.settings.value("rag_usage_date", "") != logical_today:                        self.settings.setValue("rag_usage_date", logical_today)                        self.settings.setValue("rag_usage_dict", "{}")                        self.settings.setValue("rag_exhausted_keys", "[]")                                            usage_dict = json.loads(str(self.settings.value("rag_usage_dict", "{}")))                    usage_dict[current_key] = usage_dict.get(current_key, 0) + 1                    self.settings.setValue("rag_usage_dict", json.dumps(usage_dict))                                            # --- ПРОДВИНУТЫЙ ИСТОРИЧЕСКИЙ ЛОГГЕР ---                    core_dir = os.path.dirname(os.path.abspath(__file__))                    config_dir = os.path.join(os.path.dirname(core_dir), "config", "VibeCoder")                    os.makedirs(config_dir, exist_ok=True)                    history_file = os.path.join(config_dir, "rag_usage_history.json")                                        h_data = {}                    if os.path.exists(history_file):                        try:                            with open(history_file, 'r', encoding='utf-8') as hist_f:                                h_data = json.load(hist_f)                        except: pass                                        # Инициализируем день, если его нет                    if logical_today not in h_data:                        h_data[logical_today] = {"total": 0, "keys": {}}                                            # Формируем красивое имя ключа с комментарием                    comment = EmbeddingFactory._key_comments.get(current_key, "")                    masked = f"{current_key[:6]}...{current_key[-4:]}" if len(current_key) > 10 else "***"                    key_label = f"{masked} ({comment})" if comment else masked                                        h_data[logical_today]["total"] += 1                    h_data[logical_today]["keys"][key_label] = h_data[logical_today]["keys"].get(key_label, 0) + 1                                        with open(history_file, 'w', encoding='utf-8') as hist_f:                        json.dump(h_data, hist_f, indent=4, ensure_ascii=False)                                            break                except Exception as e:                    error_text = str(e).lower()                    masked = f"...{current_key[-4:]}" if len(current_key) > 4 else "***"                                        if "quota" in error_text:                        exhausted = json.loads(str(self.settings.value("rag_exhausted_keys", "[]")))                        if current_key not in exhausted:                            exhausted.append(current_key)                            self.settings.setValue("rag_exhausted_keys", json.dumps(exhausted))                                                    if EmbeddingFactory.switch_to_next_key():                            if not self.silent:                                 self.log_signal.emit(f"⚠️ Квота ключа {masked} исчерпана! Переключение на резервный...", "#e6a822")                            self.embed_provider, _ = EmbeddingFactory.get_provider("Gemini")                            continue                         else:                            self.is_running = False                            msg = "🚨 ИСЧЕРПАНЫ ЛИМИТЫ ВСЕХ КЛЮЧЕЙ API GOOGLE."                            if not self.silent: self.log_signal.emit(msg, "#ff4444")                            self.error_signal.emit(msg)                            raise Exception("QUOTA_EXCEEDED")                                                elif "429" in error_text or "resource_exhausted" in error_text:                        if attempt < max_retries - 1:                            wait_time = base_delay * (2 ** attempt)                            if not self.silent:                                 self.log_signal.emit(f"⏳ API перегружено (RPM). Ожидание {wait_time} сек...", "#e6a822")                            for _ in range(wait_time * 2):                                if not self.is_running: return                                time.sleep(0.5)                        else:                            raise Exception(f"Превышен лимит попыток (ошибка 429): {e}")                    else:                        # 🚨 ЖЕСТКИЙ СТОП ПРИ ЛЮБЫХ ДРУГИХ ОШИБКАХ API (например, неверный ключ 400 Bad Request)                        self.is_running = False                        msg = f"🚨 Критическая ошибка ключа {masked}: {str(e)}"                        if not self.silent: self.log_signal.emit(msg, "#ff4444")                        self.error_signal.emit(f"Сбой API: Проверьте правильность резервного ключа {masked}.")                        raise Exception("CRITICAL_API_ERROR")                                    if vector is None: continue                        chunk_id = f"{rel_path}_chunk_{i}"            ids.append(chunk_id)            embeddings.append(vector)            texts.append(chunk)            metadatas.append({                "file_path": rel_path,                 "chunk_index": i,                "md5_hash": file_hash,                "last_indexed": current_time            })                    if ids:            self.db.add_chunks(ids, embeddings, texts, metadatas)    def stop(self):        self.is_running = False